ALTER TABLE users ADD COLUMN IF NOT EXISTS academy_completed boolean DEFAULT false; ALTER TABLE users ADD COLUMN IF NOT EXISTS bot_cert_passed boolean DEFAULT false; ALTER TABLE users ADD COLUMN IF NOT EXISTS hskd_passed boolean DEFAULT false; ALTER TABLE users ADD COLUMN IF NOT EXISTS clearpath_issued boolean DEFAULT false; CREATE TABLE IF NOT EXISTS certificates (id uuid PRIMARY KEY DEFAULT gen_random_uuid() NOT NULL, user_id uuid NOT NULL, type varchar(50) NOT NULL, cert_number varchar(50) UNIQUE, issued_at timestamp DEFAULT now(), created_at timestamp DEFAULT now()); CREATE TABLE IF NOT EXISTS bot_cert_questions (id uuid PRIMARY KEY DEFAULT gen_random_uuid() NOT NULL, question text NOT NULL, options jsonb NOT NULL, correct_answer_index integer NOT NULL, order_index integer NOT NULL DEFAULT 0, is_active boolean NOT NULL DEFAULT true, created_at timestamp DEFAULT now(), updated_at timestamp DEFAULT now()); CREATE TABLE IF NOT EXISTS bot_cert_responses (id uuid PRIMARY KEY DEFAULT gen_random_uuid() NOT NULL, user_id uuid NOT NULL, answers jsonb NOT NULL, score integer NOT NULL, total_questions integer NOT NULL, passed boolean NOT NULL DEFAULT false, passed_at timestamp, created_at timestamp DEFAULT now()); CREATE TABLE IF NOT EXISTS hskd_cert_questions (id uuid PRIMARY KEY DEFAULT gen_random_uuid() NOT NULL, scenario text NOT NULL, order_index integer NOT NULL DEFAULT 0, is_active boolean NOT NULL DEFAULT true, created_at timestamp DEFAULT now(), updated_at timestamp DEFAULT now()); CREATE TABLE IF NOT EXISTS hskd_cert_responses (id uuid PRIMARY KEY DEFAULT gen_random_uuid() NOT NULL, user_id uuid NOT NULL, answers jsonb NOT NULL, has_rejection boolean NOT NULL DEFAULT false, flagged_at timestamp, admin_approved boolean DEFAULT false, approved_by uuid, approved_at timestamp, created_at timestamp DEFAULT now()); CREATE INDEX IF NOT EXISTS idx_certificates_user_id ON certificates(user_id); CREATE INDEX IF NOT EXISTS idx_bot_cert_responses_user ON bot_cert_responses(user_id); CREATE INDEX IF NOT EXISTS idx_hskd_cert_responses_user ON hskd_cert_responses(user_id);
